import React, { useState, useEffect } from 'react';
import API from '../api/axios';

const UserMaster = () => {
    const [users, setUsers] = useState([]);
    const [formData, setFormData] = useState({ 
        userName: '', email: '', password: '', phoneNumber: '', role: 'User', department: '', programme: '' 
    });
    const [loading, setLoading] = useState(false);
    const [departments, setDepartments] = useState([]);
    const [programmes, setProgrammes] = useState([]);

    const roleOptions = ['SuperAdmin', 'User', 'Networking Staff', 'Plumber', 'Electrician', 'Software Developer'];

    useEffect(() => {
        fetchUsers();
        fetchDepartments();
    }, []);

    const fetchUsers = async () => {
        try {
            const { data } = await API.get('/master/users');
            setUsers(data);
        } catch (err) {
            alert('Error fetching users');
        }
    };

    const fetchDepartments = async () => {
        try {
            const { data } = await API.get('/master/department');
            setDepartments(data);
        } catch (err) {
            alert('Error fetching departments');
        }
    };

    const fetchProgrammes = async (deptId) => {
        try {
            const { data } = await API.get('/master/programme');
            const filtered = data.filter(p => p.department && p.department._id === deptId);
            setProgrammes(filtered);
        } catch (err) {
            alert('Error fetching programmes');
        }
    };

    const handleDepartmentChange = (e) => {
        const deptId = e.target.value;
        setFormData({...formData, department: deptId, programme: ''});
        fetchProgrammes(deptId);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            await API.post('/master/users', formData);
            setFormData({ userName: '', email: '', password: '', phoneNumber: '', role: 'User', department: '', programme: '' });
            fetchUsers();
            alert('User added successfully!');
        } catch (err) {
            alert('Error adding user: ' + err.response?.data?.error || err.message);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={{ padding: '40px', color: 'white', background: '#0f172a', minHeight: '100vh' }}>
            <h2 style={{ fontSize: '2rem', marginBottom: '30px' }}>User Management</h2>
            
            <form onSubmit={handleSubmit} style={{ maxWidth: '500px', marginBottom: '40px' }}>
                <div style={{ marginBottom: '15px' }}>
                    <label>User Name</label>
                    <input 
                        type="text" 
                        required
                        value={formData.userName}
                        onChange={e => setFormData({...formData, userName: e.target.value})}
                        style={inputStyle}
                    />
                </div>

                <div style={{ marginBottom: '15px' }}>
                    <label>Email</label>
                    <input 
                        type="email" 
                        required
                        value={formData.email}
                        onChange={e => setFormData({...formData, email: e.target.value})}
                        style={inputStyle}
                    />
                </div>

                <div style={{ marginBottom: '15px' }}>
                    <label>Password</label>
                    <input 
                        type="password" 
                        required
                        value={formData.password}
                        onChange={e => setFormData({...formData, password: e.target.value})}
                        style={inputStyle}
                    />
                </div>

                <div style={{ marginBottom: '15px' }}>
                    <label>Phone Number</label>
                    <input 
                        type="tel" 
                        value={formData.phoneNumber}
                        onChange={e => setFormData({...formData, phoneNumber: e.target.value})}
                        style={inputStyle}
                    />
                </div>

                <div style={{ marginBottom: '15px' }}>
                    <label>Role</label>
                    <select 
                        required
                        value={formData.role}
                        onChange={e => setFormData({...formData, role: e.target.value})}
                        style={inputStyle}
                    >
                        {roleOptions.map(role => (
                            <option key={role} value={role}>{role}</option>
                        ))}
                    </select>
                </div>

                <div style={{ marginBottom: '15px' }}>
                    <label>Department</label>
                    <select 
                        value={formData.department}
                        onChange={handleDepartmentChange}
                        style={inputStyle}
                    >
                        <option value="">Select Department</option>
                        {departments.map(dept => (
                            <option key={dept._id} value={dept._id}>{dept.department}</option>
                        ))}
                    </select>
                </div>

                <div style={{ marginBottom: '15px' }}>
                    <label>Programme</label>
                    <select 
                        value={formData.programme}
                        onChange={e => setFormData({...formData, programme: e.target.value})}
                        style={inputStyle}
                    >
                        <option value="">Select Programme</option>
                        {programmes.map(prog => (
                            <option key={prog._id} value={prog._id}>{prog.programme}</option>
                        ))}
                    </select>
                </div>

                <button type="submit" disabled={loading} style={btnStyle}>
                    {loading ? 'Adding...' : 'Add User'}
                </button>
            </form>

            <h3>Users List</h3>
            <table style={{...tableStyle, fontSize: '0.9rem'}}>
                <thead>
                    <tr>
                        <th>User Name</th>
                        <th>Email</th>
                        <th>Phone</th>
                        <th>Role</th>
                    </tr>
                </thead>
                <tbody>
                    {users.map(user => (
                        <tr key={user._id}>
                            <td>{user.userName}</td>
                            <td>{user.email}</td>
                            <td>{user.phoneNumber}</td>
                            <td>{user.role}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

const inputStyle = { 
    width: '100%', 
    padding: '10px', 
    marginTop: '5px',
    borderRadius: '5px', 
    border: '1px solid #334155', 
    background: '#1e293b', 
    color: 'white',
    boxSizing: 'border-box'
};

const btnStyle = { 
    padding: '12px 20px', 
    background: 'linear-gradient(to right, #38bdf8, #818cf8)', 
    border: 'none', 
    borderRadius: '5px', 
    color: 'white', 
    fontWeight: 'bold', 
    cursor: 'pointer',
    width: '100%'
};

const tableStyle = {
    width: '100%',
    borderCollapse: 'collapse',
    marginTop: '20px',
    border: '1px solid #334155'
};

export default UserMaster;
